+/** Known search engine crawler user-agent patterns */
+const CRAWLER_UA_PATTERNS = [
+  "googlebot",
+  "bingbot",
+  "slurp",
+  "duckduckbot",
+  "baiduspider",
+  "yandexbot",
+  "facebookexternalhit",
